package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;
import java.lang.reflect.Constructor;

class CartTest {

  @Test
  void testGetLineItemsReturnsCorrectList() throws Exception {
    // Use reflection to get LineItem class and instantiate objects
    Class<?> lineItemClass = Class.forName("com.google.gson.examples.android.model.LineItem");
    Object item1 = lineItemClass.getDeclaredConstructor().newInstance();
    Object item2 = lineItemClass.getDeclaredConstructor().newInstance();

    List<Object> items = new ArrayList<>();
    items.add(item1);
    items.add(item2);

    // Use reflection to get Cart constructor and instantiate Cart
    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");
    Constructor<?> cartConstructor = cartClass.getConstructor(List.class, String.class, String.class);
    Object cart = cartConstructor.newInstance(items, "buyerName", "creditCard123");

    // Use reflection to invoke getLineItems method
    @SuppressWarnings("unchecked")
    List<Object> result = (List<Object>) cartClass.getMethod("getLineItems").invoke(cart);

    assertNotNull(result);
    assertEquals(2, result.size());
    assertSame(item1, result.get(0));
    assertSame(item2, result.get(1));
  }
}
